export function nextGeneration(grid: number[][]): number[][] {
  const liveSet = new Set(grid.map(([x, y]) => `${x},${y}`));
  const candidates = new Map<string, [number, number]>();

  for (const [x, y] of grid) {
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        if (dx === 0 && dy === 0) continue;
        const nx = x + dx;
        const ny = y + dy;
        candidates.set(`${nx},${ny}`, [nx, ny]);
      }
    }
  }

  for (const [x, y] of grid) {
    candidates.set(`${x},${y}`, [x, y]);
  }

  const result: number[][] = [];
  for (const [key, [x, y]] of candidates) {
    let neighbors = 0;
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        if (dx === 0 && dy === 0) continue;
        if (liveSet.has(`${x + dx},${y + dy}`)) neighbors++;
      }
    }
    const isAlive = liveSet.has(key);
    if (isAlive && (neighbors === 2 || neighbors === 3)) {
      result.push([x, y]);
    } else if (!isAlive && neighbors === 3) {
      result.push([x, y]);
    }
  }

  return result;
}
